firmware_template.source:
#include "dumbdisplay_bt.h"
#include "dumbdisplay.h"
#include "esp32dumbdisplay.h"

static DDBluetoothSerialIO* ddio = nullptr;
static DumbDisplay* dd = nullptr;
static LcdDDLayer* lcd = nullptr;
static GraphicalDDLayer* gfx = nullptr;

void dd_bt_setup(const char* bt_name) {
  ddio = new DDBluetoothSerialIO(bt_name, true);
  dd = new DumbDisplay(ddio);
  Serial.println("[dd_bt] Bluetooth ready, pair phone");
}

void dd_bt_loop() { /* DumbDisplay handles loop internally */ }

void dd_bt_create_lcd(int cols, int rows) {
  lcd = dd->createLcdLayer(cols, rows);
}

void dd_bt_create_graphical(int width, int height) {
  gfx = dd->createGraphicalLayer(width, height);
}

void dd_bt_lcd_print(int col, int row, const char* text) {
  if (!lcd) return;
  lcd->setCursor(col, row);
  lcd->print(text);
}

void dd_bt_lcd_clear() {
  if (!lcd) return;
  lcd->clear();
}

void dd_bt_gfx_line(int x1, int y1, int x2, int y2, const char* color) {
  if (!gfx) return;
  gfx->drawLine(x1, y1, x2, y2, color);
}

void dd_bt_gfx_rect(int x, int y, int w, int h, const char* color, bool fill) {
  if (!gfx) return;
  if (fill) gfx->fillRect(x, y, w, h, color);
  else gfx->drawRect(x, y, w, h, color);
}

void dd_bt_gfx_circle(int x, int y, int r, const char* color, bool fill) {
  if (!gfx) return;
  if (fill) gfx->fillCircle(x, y, r, color);
  else gfx->drawCircle(x, y, r, color);
}

void dd_bt_gfx_text(int x, int y, const char* text, const char* color, int size) {
  if (!gfx) return;
  gfx->setTextColor(color);
  gfx->setTextSize(size);
  gfx->drawStr(x, y, text);
}

void dd_bt_auto_pin(const char* layout) {
  dd->configAutoPin(layout);
}
